const SeasonCard = ({headerLabel, header, bodyLabel, bodyText} : any) => {
    return(
        <>
            <div className="card">
                <div className="card-body">
                    <h5 className="card-title">{headerLabel + ":" + header}</h5>
                    <p className="card-text">{bodyLabel + ":" + bodyText}</p>
                </div>
            </div>

        </>
    )
}

export default SeasonCard;
